31	const COMPONENT_BASE_PREMIUM = 25;
32	
33	const BASE_PREMIUMS: Record<string, number> = {
34	  sword: 100,
35	  amulet: 60,
36	  staff: 80,
37	  potion: 40,
38	  rune: COMPONENT_BASE_PREMIUM,
39	  moonstone: COMPONENT_BASE_PREMIUM,
40	};
41	
42	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
43	const BLOCK_SIZE = 3;
44	const BLOCK_PREMIUM = 60;
45	
46	const formsBlock = (type: string, count: number): boolean =>
47	  COMPONENT_TYPES.has(type) && count === BLOCK_SIZE;
48	
49	const typeBasePremium = (type: string, count: number): number => {
50	  if (formsBlock(type, count)) return BLOCK_PREMIUM;
51	  return count * BASE_PREMIUMS[type];
52	};
53	
54	const policyBasePremium = (items: Item[]): number => {
55	  const counts = new Map<string, number>();
56	  for (const item of items) {
57	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
58	  }
59	  return [...counts].reduce(
60	    (base, [type, count]) => base + typeBasePremium(type, count),
61	    0,
62	  );
63	};
64	
65	const CURSE_SURCHARGE = 0.5;
66	const HIGH_ENCHANTMENT_SURCHARGE = 0.3;
67	const HIGH_ENCHANTMENT_THRESHOLD = 5;
68	
69	const SURCHARGE_RULES: { applies: (item: Item) => boolean; rate: number }[] = [
70	  { applies: (item) => item.cursed === true, rate: CURSE_SURCHARGE },
71	  {
72	    applies: (item) => (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
73	    rate: HIGH_ENCHANTMENT_SURCHARGE,
74	  },
75	];
76	
77	const itemSurchargeRate = (item: Item): number =>
78	  SURCHARGE_RULES.reduce(
79	    (rate, rule) => (rule.applies(item) ? rate + rule.rate : rate),
80	    0,
81	  );
82	
83	const itemSurcharge = (item: Item): number =>
84	  itemSurchargeRate(item) * BASE_PREMIUMS[item.type];
85	
86	const itemSurcharges = (items: Item[]): number =>
87	  items.reduce((sum, item) => sum + itemSurcharge(item), 0);
88	
89	// Premiums round up (in the MHPCO's favor); toFixed guards against
90	// floating-point error nudging an exact value over an integer boundary.
91	const roundUpPremium = (amount: number): number =>
92	  Math.ceil(Number(amount.toFixed(6)));
93	
94	const quotePremium = (step: QuoteStep, customer: Customer): number => {
95	  const { items } = step;
96	  const policyBase = policyBasePremium(items);
97	  const loyaltyDiscount =
98	    customer.yearsWithMHPCO >= LOYALTY_THRESHOLD ? policyBase * LOYALTY_DISCOUNT : 0;
99	  const total =
100	    policyBase +
101	    itemSurcharges(items) +
102	    policyBase * FIRST_INSURANCE_SURCHARGE -
103	    loyaltyDiscount +
104	    PROCESSING_FEE;
105	  return roundUpPremium(total);
106	};
107	
108	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => {
109	  return {
110	    results: scenario.steps.map((step) => ({
111	      premium: quotePremium(step, scenario.customer),
112	    })),
113	  };
114	};
