// Policy-wide modifiers each apply a signed rate to the policy base:
// positive rates are surcharges, negative rates are discounts.
const POLICY_MODIFIER_RULES: {
  applies: (customer: Customer) => boolean;
  rate: number;
}[] = [
  { applies: () => true, rate: FIRST_INSURANCE_SURCHARGE },
  {
    applies: (customer) => customer.yearsWithMHPCO >= LOYALTY_THRESHOLD,
    rate: -LOYALTY_DISCOUNT,
  },
];

const policyModifierRate = (customer: Customer): number =>
  POLICY_MODIFIER_RULES.reduce(
    (rate, rule) => (rule.applies(customer) ? rate + rule.rate : rate),
    0,
  );

// Premiums round up (in the MHPCO's favor); toFixed guards against
// floating-point error nudging an exact value over an integer boundary.
const roundUpPremium = (amount: number): number =>
  Math.ceil(Number(amount.toFixed(6)));

const quotePremium = (step: QuoteStep, customer: Customer): number => {
  const { items } = step;
  const policyBase = policyBasePremium(items);
  const total =
    policyBase +
    itemSurcharges(items) +
    policyBase * policyModifierRate(customer) +
    PROCESSING_FEE;
  return roundUpPremium(total);
};
